using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpServer;

// The [McpServerToolType] attribute registers this class as a container for MCP tools.
// The MCP SDK scans for this at startup and wires each [McpServerTool] method into the
// tool registry so LLM clients can discover and invoke them.
[McpServerToolType]
public class WeatherTools
{
    // Constructor-injected dependencies — the MCP SDK resolves these from the DI
    // container every time a tool is invoked (tools are transient by default).
    private readonly HttpClient _http;

    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    [McpServerTool, Description("Get current weather for a city using the wttr.in API.")]
    public async Task<string> GetWeather(
        [Description("City name, e.g. 'Seattle' or 'London'")] string city,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var url = $"https://wttr.in/{Uri.EscapeDataString(city)}?format=j1";
            var data = await _http.GetFromJsonAsync<WttrResponse>(url, cancellationToken);

            if (data?.CurrentCondition is not [var current, ..])
                return $"No weather data found for '{city}'.";

            return $"""
                Weather for {city}:
                  Temperature: {current.TempC}°C ({current.TempF}°F)
                  Condition:   {current.WeatherDesc?.FirstOrDefault()?.Value ?? "Unknown"}
                  Humidity:    {current.Humidity}%
                  Wind:        {current.WindspeedKmph} km/h {current.WindDir}
                """;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch weather for '{city}': {ex.Message}";
        }
    }

    [McpServerTool, Description("Compare weather between two cities.")]
    public async Task<string> CompareWeather(
        [Description("First city name")] string cityA,
        [Description("Second city name")] string cityB,
        CancellationToken cancellationToken = default)
    {
        // Fan out both requests concurrently.
        var results = await Task.WhenAll(
            GetWeather(cityA, cancellationToken),
            GetWeather(cityB, cancellationToken));

        return $"{results[0]}\n---\n{results[1]}";
    }
}

// Minimal DTOs for the wttr.in JSON response.
public record WttrResponse(
    [property: JsonPropertyName("current_condition")]
    List<CurrentCondition>? CurrentCondition);

public record CurrentCondition(
    [property: JsonPropertyName("temp_C")] string? TempC,
    [property: JsonPropertyName("temp_F")] string? TempF,
    [property: JsonPropertyName("humidity")] string? Humidity,
    [property: JsonPropertyName("windspeedKmph")] string? WindspeedKmph,
    [property: JsonPropertyName("winddir16Point")] string? WindDir,
    [property: JsonPropertyName("weatherDesc")] List<WeatherDesc>? WeatherDesc);

public record WeatherDesc(
    [property: JsonPropertyName("value")] string? Value);

